#include<bits/stdc++.h>
using namespace std;
struct node
{
    int son[131],cnt;
}t[3000010];
int tot=0;
char s[100010];
void insert(char s[])
{
    int p=0;
    for(int i=0;s[i];i++)
    {
        int &v=t[p].son[s[i]];
        if(!v)
        {
            v=++tot;
            for(int i=0;i<=130;i++)
            {
                t[v].son[i]=0;
            }
            t[v].cnt=0;
        }
        p=v;
        t[p].cnt++;
    }
}
int query(char s[])
{
    int p=0;
    for(int i=0;s[i];i++)
    {
        int &v=t[p].son[s[i]];
        if(!v)
        {
            return 0;
        }
        p=v;
    }
    return t[p].cnt;
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        tot=0;
        for(int i=0;i<=130;i++)
        {
            ::t[0].son[i]=0;
        }
        ::t[0].cnt=0;
        int n,q;
        scanf("%d%d",&n,&q);
        for(int i=1;i<=n;i++)
        {
            scanf("%s",s+1);
            insert(s+1);
        }
        for(int i=1;i<=q;i++)
        {
            scanf("%s",s+1);
            printf("%d\n",query(s+1));
        }
    }
    return 0;
}
